import { Image, Linking, Pressable, StyleSheet, Text, View } from 'react-native';
import { Ionicons } from '@expo/vector-icons';
import Svg, { Defs, LinearGradient, Rect, Stop } from 'react-native-svg';
import { Badge } from '../../components/ui/Badge';
import { colors, gradients } from '../../theme/colors';
import { vendorCatalogStyles as styles } from './vendorCatalogStyles';
import type { VendorRecord } from './vendorCatalogModel';

export function VendorCard({ item, index, total, gradientId, edit, remove, move }: { item: VendorRecord; index: number; total: number; gradientId: string; edit: () => void; remove: () => void; move: (direction: 'up' | 'down') => void }) {
  const contact = (kind: 'call' | 'whatsapp' | 'email', value: string) => { const url = kind === 'call' ? `tel:${value}` : kind === 'whatsapp' ? `https://wa.me/${value.replace(/\D/g, '')}` : `mailto:${value}`; void Linking.openURL(url); };
  return <View style={styles.vendorCard}><View style={styles.vendorImageWrap}>{item.cover_image_url ? <Image source={{ uri: item.cover_image_url }} style={styles.vendorImage} resizeMode="cover" /> : <View style={styles.vendorImagePlaceholder}><Svg style={StyleSheet.absoluteFill}><Defs><LinearGradient id={`vc-ph-${gradientId}-${item.id}`} x1="0" y1="0" x2="1" y2="1"><Stop offset="0" stopColor={gradients.royal[0]} /><Stop offset="1" stopColor={gradients.royal[1]} /></LinearGradient></Defs><Rect width="100%" height="100%" fill={`url(#vc-ph-${gradientId}-${item.id})`} /></Svg><Ionicons name="storefront" size={32} color="#FFFFFF" /></View>}<Svg style={styles.vendorImageOverlay}><Defs><LinearGradient id={`vc-ov-${gradientId}-${item.id}`} x1="0" y1="1" x2="0" y2="0"><Stop offset="0" stopColor="rgba(0,0,0,0.7)" /><Stop offset="1" stopColor="transparent" /></LinearGradient></Defs><Rect width="100%" height="100%" fill={`url(#vc-ov-${gradientId}-${item.id})`} /></Svg><View style={styles.vendorImageOverlayContent}><Text style={styles.vendorImageName} numberOfLines={1}>{item.name}</Text>{item.city || item.state ? <Text style={styles.vendorImageLocation}><Ionicons name="location" size={11} color="rgba(255,255,255,0.8)" /> {[item.city, item.state].filter(Boolean).join(', ')}</Text> : null}</View><View style={styles.vendorBadges}><Badge variant="royal" size="sm" label={item.category} />{item.is_visible_in_vitrine ? <Badge variant="gold" size="sm" label="Vitrine" /> : null}</View>{item.price_range ? <View style={styles.priceTag}><Text style={styles.priceTagText}>{item.price_range}</Text></View> : null}</View><View style={styles.vendorCardBody}><View style={styles.contactRow}>{item.phone ? <Pressable style={styles.contactAction} onPress={() => contact('call', item.phone!)}><Ionicons name="call" size={18} color={colors.primaryStrong} /></Pressable> : null}{item.whatsapp ? <Pressable style={[styles.contactAction, styles.contactActionGreen]} onPress={() => contact('whatsapp', item.whatsapp!)}><Ionicons name="logo-whatsapp" size={18} color="#22c55e" /></Pressable> : null}{item.email ? <Pressable style={styles.contactAction} onPress={() => contact('email', item.email!)}><Ionicons name="mail" size={18} color={colors.primaryStrong} /></Pressable> : null}</View><View style={styles.vendorActions}><View style={styles.reorderGroup}><Pressable style={[styles.reorderBtn, index === 0 && styles.reorderBtnDisabled]} onPress={() => move('up')} disabled={index === 0}><Ionicons name="chevron-up" size={16} color={index ? colors.text : colors.mutedText} /></Pressable><Text style={styles.orderLabel}>#{item.display_order + 1}</Text><Pressable style={[styles.reorderBtn, index === total - 1 && styles.reorderBtnDisabled]} onPress={() => move('down')} disabled={index === total - 1}><Ionicons name="chevron-down" size={16} color={index < total - 1 ? colors.text : colors.mutedText} /></Pressable></View><View style={styles.actionGroup}><Pressable style={styles.editBtn} onPress={edit}><Ionicons name="create-outline" size={18} color={colors.primaryStrong} /><Text style={styles.editBtnText}>Editar</Text></Pressable><Pressable style={styles.deleteBtn} onPress={remove}><Ionicons name="trash-outline" size={18} color={colors.dangerText} /></Pressable></View></View></View></View>;
}
